1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return an empty grid when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell due to underpopulation", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells due to underpopulation", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block unchanged as a still life", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(result).toHaveLength(4);
17	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
18	  });
19	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
20	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
21	    expect(result).toHaveLength(3);
22	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
23	  });
24	  it("should kill cells with more than 3 live neighbors due to overpopulation", () => {
25	    // Input pattern: ### / .#. / ### — center (1,1) has 6 live neighbors → dies (overpopulation).
26	    // Surviving live cells: (0,0),(2,0) with 2 neighbors; (1,0),(1,2) with 3 neighbors; (0,2),(2,2) with 2 neighbors.
27	    // Born cells (dead with exactly 3 live neighbors): (1,-1) and (1,3).
28	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]]);
29	    expect(result).not.toEqual(expect.arrayContaining([[1, 1]]));
30	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [2, 0], [0, 2], [1, 2], [2, 2]]));
31	  });
32	  it.todo("should bring a dead cell with exactly 3 live neighbors to life by reproduction");
33	});
